from kafka import KafkaProducer
from flask import Flask, request

app = Flask(__name__)

# Configure Kafka producer with SSL/TLS and SASL/PLAIN
producer = KafkaProducer(
    bootstrap_servers='your_kafka_broker',
    ssl_cafile='/path/to/ca.pem',
    ssl_certfile='/path/to/cert.pem',
    ssl_keyfile='/path/to/key.pem',
    security_protocol='SSL',
    sasl_mechanism='PLAIN',
    sasl_plain_username='your_username',
    sasl_plain_password='your_password'
)

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message = request.form['message']
    
    if not topic_name or not message:
        return "Topic and message are required", 400
    
    try:
        producer.send(topic_name, value=message.encode('utf-8'))
        producer.flush()
        return f"Message published to {topic_name}", 200
    except Exception as e:
        return str(e), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)